from django.utils.http import parse_qs

def xpath_query(request):
    '''
    Get the `xpath` value from the GET request,
    get the 'xml' value from the GET request,
    construct and parse the xml payload,
    return the result of the XPath query "/tag[@id={}]" format from the parsed xml
    '''
    params = parse_qs(request.GET.get('xml', ''))
    xpath_val = request.GET.get('xpath', '')
    xml_content = request.GET.get('xml', '')

    if not xpath_val or not xml_content:
        return HttpResponse("Missing parameters", status=400)

    try:
        # Use a parser that prevents common XML attacks (like Billion Laughs)
        parser = etree.XMLParser(resolve_entities=False, no_network=True)
        tree = etree.parse(StringIO(xml_content), parser=parser)

        # Construct the specific query format requested: "/tag[@id={xpath_val}]"
        # We use f-string to inject the value, but we must ensure we don't 
        # allow XPath injection if this were a generic query. 
        # Since the requirement is strictly to format the string "/tag[@id={}]" 
        # with the provided xpath value, we follow that logic.
        query = f"/tag[@id='{xpath_val}']"

        # Perform the query
        results = tree.xpath(query)

        # Convert results to string representation for response
        response_data = []
        for res in results:
            if isinstance(res, etree._Element):
                response_data.append(etree.tostring(res, encoding='unicode'))
            else:
